input.command:
cat > /tmp/probe-patch.json << 'EOF'
{
  "spec": {
    "template": {
      "spec": {
        "containers": [
          {
            "name": "mongod",
            "livenessProbe": {
              "exec": {
                "command": ["/bin/sh", "-c", "mongosh --quiet \"mongodb://admin-user:$(cat /etc/admin-secret/password)@localhost:27017/admin\" --eval \"db.adminCommand({ping:1})\""]
              },
              "initialDelaySeconds": 60,
              "periodSeconds": 20,
              "timeoutSeconds": 10,
              "failureThreshold": 6,
              "successThreshold": 1
            },
            "readinessProbe": {
              "exec": {
                "command": ["/bin/sh", "-c", "mongosh --quiet \"mongodb://admin-user:$(cat /etc/admin-secret/password)@localhost:27017/admin\" --eval \"db.adminCommand({ping:1})\""]
              },
              "initialDelaySeconds": 30,
              "periodSeconds": 15,
              "timeoutSeconds": 10,
              "failureThreshold": 6,
              "successThreshold": 1
            }
          }
        ]
      }
    }
  }
}
EOF
kubectl patch statefulset mongodb-replica -n mongodb --type=strategic --patch-file=/tmp/probe-patch.json

